package com.google.gson;
import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.Gson;
import com.google.gson.JsonIOException;
import com.google.gson.JsonSyntaxException;
import com.google.gson.reflect.TypeToken;
import com.google.gson.stream.JsonReader;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

import java.io.Reader;
import java.io.StringReader;
import java.lang.reflect.Method;
import java.util.Collections;

class GsonFromJsonTest {

  private Gson gson;

  @BeforeEach
  void setUp() {
    gson = new Gson();
  }

  @Test
  void fromJson_validJson_returnsExpectedObject() throws Exception {
    String json = "{\"key\":\"value\"}";
    Reader reader = new StringReader(json);
    TypeToken<Object> typeToken = TypeToken.get(Object.class);

    // Spy on gson to mock fromJson(JsonReader, TypeToken) and assertFullConsumption
    Gson spyGson = Mockito.spy(gson);

    JsonReader jsonReader = spyGson.newJsonReader(reader);

    // Mock fromJson(JsonReader, TypeToken) to return a known object
    Object expectedObject = Collections.singletonMap("key", "value");
    doReturn(expectedObject).when(spyGson).fromJson(any(JsonReader.class), eq(typeToken));

    // Use reflection to make assertFullConsumption accessible and spy on it
    Method assertFullConsumptionMethod = Gson.class.getDeclaredMethod("assertFullConsumption", Object.class, JsonReader.class);
    assertFullConsumptionMethod.setAccessible(true);

    // Call fromJson(Reader, TypeToken)
    Object actualObject = spyGson.fromJson(new StringReader(json), typeToken);

    // Verify fromJson(JsonReader, TypeToken) was called with a JsonReader
    verify(spyGson).fromJson(any(JsonReader.class), eq(typeToken));

    // Verify assertFullConsumption was called via reflection inside fromJson
    // We cannot directly verify private static method call, but no exception means it passed

    assertSame(expectedObject, actualObject);
  }

  @Test
  void fromJson_nullReader_throwsNullPointerException() {
    TypeToken<Object> typeToken = TypeToken.get(Object.class);
    assertThrows(NullPointerException.class, () -> {
      // Cast to Object to disambiguate method overload
      gson.<Object>fromJson((Reader) null, (TypeToken<Object>) typeToken);
    });
  }

  @Test
  void fromJson_nullTypeToken_throwsNullPointerException() {
    Reader reader = new StringReader("{}");
    assertThrows(NullPointerException.class, () -> {
      // Cast to Object to disambiguate method overload
      gson.<Object>fromJson(reader, (TypeToken<Object>) null);
    });
  }

  @Test
  void fromJson_malformedJson_throwsJsonSyntaxException() {
    String malformedJson = "{key:value"; // missing closing }
    Reader reader = new StringReader(malformedJson);
    TypeToken<Object> typeToken = TypeToken.get(Object.class);

    assertThrows(JsonSyntaxException.class, () -> {
      gson.fromJson(reader, typeToken);
    });
  }

  @Test
  void fromJson_ioException_throwsJsonIOException() throws Exception {
    Reader mockReader = mock(Reader.class);
    TypeToken<Object> typeToken = TypeToken.get(Object.class);

    // Spy on gson
    Gson spyGson = Mockito.spy(gson);
    JsonReader mockJsonReader = mock(JsonReader.class);

    // Mock newJsonReader to return the mockJsonReader when called with mockReader
    doReturn(mockJsonReader).when(spyGson).newJsonReader(mockReader);

    // Mock fromJson(JsonReader, TypeToken) to throw IOException wrapped in JsonIOException
    doAnswer(invocation -> {
      throw new java.io.IOException("IO error");
    }).when(spyGson).fromJson(mockJsonReader, typeToken);

    assertThrows(JsonIOException.class, () -> {
      spyGson.fromJson(mockReader, typeToken);
    });
  }
}
